INSERT INTO public.page_content (page_slug, field_key, field_value) VALUES

-- ═══════════════════════════════════════════════
-- PAGE: imat-ultimate-guide
-- ═══════════════════════════════════════════════

('imat-ultimate-guide', 'hero_headline', 'The Ultimate IMAT 2026 Guide: Your Path to Medical School in Italy'),

('imat-ultimate-guide', 'hero_desc', 'Italy has become the premier destination for international students seeking world-class Medical and Dental education in English. As the 2026 cycle approaches, the competition is higher than ever. Our comprehensive 2000-word authority guide provides the strategic blueprint needed to navigate admission requirements, competitive quotas, and the exam itself.'),

('imat-ultimate-guide', 'section_history_title', '1. The Evolution of English-taught Medicine in Italy'),
('imat-ultimate-guide', 'section_history_body', 'English-taught medical programs (MD in Medicine and Surgery) in Italy began in 2009 with the Università degli Studi di Pavia. Since then, the ecosystem has expanded to over 15 public universities and several private institutions (Humanitas, San Raffaele, UniCamillus). The IMAT (International Medical Admissions Test) was established as the standardized entry barrier to ensure academic quality across all public medical schools. In 2026, we anticipate continued growth in available seats, though the competitive ratio for Non-EU students remains tight. Why Italy? High academic standards, clinical rotations at some of the world’s oldest hospitals, and tuition fees ranging from €156 to €4,000 per year (based on family income) make it an unrivaled choice for aspiring doctors.'),

('imat-ultimate-guide', 'section_eligibility_title', '2. Eligibility & Documentation: The Bureaucratic Minefield'),
('imat-ultimate-guide', 'section_eligibility_body', 'To sit the IMAT 2026 and eventually enroll, you must meet stringent eligibility criteria. 
1. **Academic Qualification**: A high school diploma obtained after 12 years of schooling. If your country has an 11-year system, you must provide proof of foundation years or university credits to bridge the gap.
2. **Dichiarazione di Valore (DoV) / CIMEA**: This is a core requirement. Italian authorities must "equalize" your local qualification. In 2026, we strongly recommend using the CIMEA Statement of Comparability as it is typically faster than the Embassy-issued DoV.
3. **Language Requirements**: While the degree is in English, most universities require no official IELTS/TOEFL score for the application, as the IMAT itself acts as a language proficiency filter. However, for visa purposes (especially for Non-EU students), a B2 level certificate is often non-negotiable for the Italian consulate.
4. **The No-IELTS Path**: Note that ItaloStudy tracks over 40 programs where MOI (Medium of Instruction) certificates are accepted instead of IELTS for 2026 applicants.'),

('imat-ultimate-guide', 'section_quota_title', '3. Understanding Quotas: EU vs. Non-EU Strategics'),
('imat-ultimate-guide', 'section_quota_body', 'One of the most common mistakes is misunderstanding the quota system. 
- **EU / EU-Equivalent Quota**: Includes all European Union citizens and foreigners with long-term Italian residence permits. In 2025, universities like Bologna and Milan Statale had significantly higher cutoffs for EU students.
- **Non-EU Quota**: Reserved for international students residing abroad. These quotas are specific to each university. For example, some universities might offer 40 seats for EU and only 10 for Non-EU.
**Strategy Tip for 2026**: Since Non-EU students only compete against other Non-EU students *at their first-choice university*, selecting the right first choice is more critical than the IMAT score itself.'),

('imat-ultimate-guide', 'section_financial_title', '4. Financial Planning & DSU Scholarships'),
('imat-ultimate-guide', 'section_financial_body', 'Medical school in Italy is subsidized by the government. 
- **Tuition**: Calculated based on the ISEE-Parificato (Equivalent Economic Situation Indicator). Most international students fall into the lowest brackets, paying less than €1,000/year.
- **DSU Scholarships**: Regional bodies (like Edisu for Turin, Ergo for Bologna) offer "Full Rides". These cover tuition waiver, one free meal a day, and a cash stipend of approx. €5,000–€7,000. 
- **Official Warning**: These scholarships are based on *need*, not merit. You must have your family financial documents legalized and translated by the end of July 2026 to be eligible.'),

('imat-ultimate-guide', 'section_structure_title', '5. The IMAT Structure & 2026 Projections'),
('imat-ultimate-guide', 'section_structure_body', 'The IMAT is a paper-based exam consisting of 60 multiple-choice questions to be completed in 100 minutes. 
- **Biology (15-18 questions)**: The most critical subject.
- **Chemistry (12-15 questions)**: Strong focus on organic chemistry.
- **Physics & Mathematics (10-15 questions)**: Often the lowest average scoring section.
- **General Knowledge & Logic (10-15 questions)**: Tests critical thinking and problem-solving.
**2026 Projection**: Following the 2024–2025 pattern where Cambridge Assessment was replaced by the Italian CINECA/MUR administration, we expect questions to be more scientifically dense and slightly less logic-dependent than the "Cambridge-era" exams.'),

-- ═══════════════════════════════════════════════
-- PAGE: imat-detailed-syllabus-2026
-- ═══════════════════════════════════════════════

('imat-detailed-syllabus-2026', 'hero_headline', 'IMAT Syllabus 2026: Topic-by-Topic Scientific Breakdown'),
('imat-detailed-syllabus-2026', 'hero_desc', 'Mastering the IMAT isn’t about reading entire textbooks; it’s about tactical mastery of high-yield subjects. Based on the latest Ministerial Decrees (MUR), here is the detailed 1800-word breakdown of every topic you need for 2026.'),

('imat-detailed-syllabus-2026', 'section_bio_title', 'Biology: The Foundation of Your Score'),
('imat-detailed-syllabus-2026', 'section_bio_body', 'Biology accounts for approximately 30-35% of the total maximum score. Success here is non-negotiable.
- **The Chemistry of Life**: Bio-elements (C, H, N, O, P, S). Properties of water. Biomolecules: carbohydrates, lipids, proteins (amino acids), and nucleic acids (nucleotides).
- **Cell Biology**: The cell theory. Structure of eukaryotic and prokaryotic cells. Cell organelles: ribosomes, Golgi apparatus, mitochondria, lysosomes, plastids, vacuole, ER. Cell membranes: fluid mosaic model, active and passive transport.
- **Bioenergetics**: ATP and the ATP cycle. Cellular respiration (aerobic and anaerobic). Photosynthesis (light and dark phases).
- **Reproduction & Inheritance**: The cell cycle (interphase, mitosis). Meiosis. Mendelian genetics (Monohybrid and dihybrid crosses). Molecular genetics (DNA replication, transcription, translation). Mutations.
- **Human Anatomy & Physiology**: The study of systems: skeletal, muscular, circulatory (heart/blood), respiratory, digestive, excretory, nervous, endocrine, and reproductive systems. Homeostasis mechanism.
- **Strategy for 2026**: Focus heavily on **Genetics and Endocrinology**. Historical analysis of IMAT 2023–2025 shows these areas are involved in over 40% of the Biology questions.'),

('imat-detailed-syllabus-2026', 'section_chem_title', 'Chemistry: Quantitative & Qualitative Deep Dive'),
('imat-detailed-syllabus-2026', 'section_chem_body', 'Chemistry questions often determine the top 5% of candidates due to the requirement for rapid mental calculation.
- **Matter & Atomic Structure**: States of matter. Atomic models (Bohr, Quantum mechanical). Periodic Table: periods, groups, electronegativity, ionization energy.
- **Chemical Bonding**: Ionic, covalent (polar/non-polar), metallic. Weak intermolecular forces (Hydrogen bonds, Van der Waals).
- **Redox Reactions**: Oxidation numbers. Balancing redox equations.
- **Stoichiometry**: The mole concept. Avogadro''s constant. Empirical and molecular formulas. Gas laws.
- **Equilibrium & Kinetics**: The law of mass action. Le Chatelier''s principle. Activation energy.
- **Organic Chemistry**: Alkanes, alkenes, alkynes. Functional groups (alcohols, aldehydes, ketones, carboxylic acids, amines, ethers). Isomerism.
**Official Resource**: Use the *Pearson Chemistry* or *Campbell Biology* textbooks to ensure you align with European university standards.'),

('imat-detailed-syllabus-2026', 'section_physics_title', 'Physics & Mathematics: The Rank Climber'),
('imat-detailed-syllabus-2026', 'section_physics_body', 'Most medical applicants are Biology-heavy and Physics-light. Mastering these topics provides a massive competitive advantage.
- **Physics**: Units of measurement. Kinematics (scalars, vectors). Dynamics (Newton’s laws, work, power, kinetic/potential energy). Fluid dynamics (density, pressure, Archimedes’ principle). Thermodynamics. Electricity (Ohm’s law, Joule effect, circuits). Electromagnetism.
- **Maths**: Arithmetic and Algebra (logarithms, powers). Functional analysis (trigonometry, exponentials). Geometry (circles, Pythagoras, coordinates). Probability and Statistics.
**Data Insight**: Since calculators are banned in the IMAT, 2026 applicants should focus on "mental estimation" of square roots and trig values (sin/cos of 30, 45, 60 degrees).'),

('imat-detailed-syllabus-2026', 'section_logic_title', 'General Knowledge & Logical Reasoning'),
('imat-detailed-syllabus-2026', 'section_logic_body', 'This section tests your ability to process information rather than recall facts.
- **General Knowledge**: History, Literature, Philosophy, Arts, and Current Affairs. (Focus on European history 19th-21st century).
- **Logical Reasoning**: Critical thinking. Identifying flaws in arguments. Drawing conclusions. Syllogisms. Numerical logic (sequences and patterns).
**2026 Update**: The General Knowledge component has shifted since 2024 to reward those who are well-read in the Humanities rather than those who memorize trivia.'),

